const l = widthMm * mm
const w = heightMm * mm
const t = thicknessMm * mm
const group = new THREE.Group()
const geo = new THREE.BoxGeometry(l, w, t)
geo.translate(l / 2, 0, 0)
group.add(new THREE.Mesh(geo, new THREE.MeshLambertMaterial({ color: '#E8DCC8' })))
const gMm = 40
const holeR = 4 * mm
const holeMat = new THREE.MeshBasicMaterial({ color: '#2a1a0a' })
const cols = Math.max(1, Math.round(widthMm / gMm))
const rows = Math.max(1, Math.round(heightMm / gMm))
for (let c = 0; c < cols; c++) {
  for (let r = 0; r < rows; r++) {
    const hx = c * gMm * mm
    const hy = (r - (rows - 1) / 2) * gMm * mm
    for (const zs of [1, -1]) {
      const d = new THREE.Mesh(new THREE.CircleGeometry(holeR, 12), holeMat)
      d.position.set(hx, hy, zs * (t / 2 + 5e-4))
      if (zs < 0) d.rotation.y = Math.PI
      group.add(d)
    }
  }
}
return group
